import React, { useEffect, useState } from "react";
import { Table, Tabs, Badge } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { getLowStockProducts, getExpiringSoonProducts } from "../../features/b2b/b2bSlice";
import { AlertTriangle, ShieldAlert, Clock, PackageX } from "lucide-react";

const InventoryAlerts = () => {
  const dispatch = useDispatch();
  const [activeTab, setActiveTab] = useState("lowStock");

  useEffect(() => {
    dispatch(getLowStockProducts());
    dispatch(getExpiringSoonProducts(90)); // default 90 days
  }, [dispatch]);

  const { lowStockProducts, expiringProducts, isLoading } = useSelector(
    (state) => state.b2b
  );

  const columns = [
    {
      title: "Product Description",
      dataIndex: "title",
      render: (title, record) => (
        <div className="flex flex-col">
          <Link
            to={`/admin/product/${record.id}`} // assuming detail link exists or edit page
            className="font-bold text-slate-900 text-sm hover:text-blue-600 transition-colors"
          >
            {title}
          </Link>
          <span className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mt-1">
            SKU: {record.sku || "N/A"} | Generic: {record.genericName || "N/A"}
          </span>
        </div>
      ),
    },
    {
      title: "Category",
      dataIndex: "b2bCategory",
      render: (cat) => (
        <span className="px-2.5 py-1 bg-slate-50 border border-slate-100 rounded-lg text-slate-500 font-bold text-xs uppercase tracking-wider">
          {cat?.replace(/_/g, " ") || "UNCATEGORIZED"}
        </span>
      ),
    },
    {
      title: "Stock Level",
      dataIndex: "quantity",
      render: (qty) => (
        <span
          className={`font-black text-sm ${
            qty === 0 ? "text-rose-600 animate-pulse" : "text-amber-600"
          }`}
        >
          {qty} Units
        </span>
      ),
    },
    {
      title: activeTab === "expiring" ? "Expiry Date" : "Reorder Level",
      render: (_, record) => {
        if (activeTab === "expiring") {
          const daysLeft = Math.ceil(
            (new Date(record.expiryDate) - new Date()) / (1000 * 60 * 60 * 24)
          );
          return (
            <div className="flex flex-col">
              <span className="font-bold text-rose-500 text-xs">
                {new Date(record.expiryDate).toLocaleDateString()}
              </span>
              <span
                className={`text-[10px] font-black uppercase mt-1 ${
                  daysLeft <= 0 ? "text-rose-600 animate-pulse" : "text-amber-500"
                }`}
              >
                {daysLeft <= 0 ? "EXPIRED" : `${daysLeft} Days Remaining`}
              </span>
            </div>
          );
        }
        return (
          <span className="font-bold text-slate-700 text-sm">
            {record.reorderLevel} Units
          </span>
        );
      },
    },
  ];

  const lowStockData = lowStockProducts?.lowStock || [];
  const outOfStockData = lowStockProducts?.outOfStock || [];
  const expiringSoonData = expiringProducts?.expiringSoon || [];
  const alreadyExpiredData = expiringProducts?.alreadyExpired || [];

  const tabItems = [
    {
      label: (
        <span className="flex items-center gap-2 font-bold text-sm">
          <ShieldAlert size={16} />
          Low Stock ({lowStockData.length})
        </span>
      ),
      key: "lowStock",
      children: (
        <Table
          columns={columns}
          dataSource={lowStockData}
          loading={isLoading}
          rowKey="id"
          className="modern-table"
        />
      ),
    },
    {
      label: (
        <span className="flex items-center gap-2 font-bold text-sm">
          <PackageX size={16} />
          Out of Stock ({outOfStockData.length})
        </span>
      ),
      key: "outOfStock",
      children: (
        <Table
          columns={columns}
          dataSource={outOfStockData}
          loading={isLoading}
          rowKey="id"
          className="modern-table"
        />
      ),
    },
    {
      label: (
        <span className="flex items-center gap-2 font-bold text-sm">
          <Clock size={16} />
          Expiring Soon ({expiringSoonData.length + alreadyExpiredData.length})
        </span>
      ),
      key: "expiring",
      children: (
        <div className="space-y-8">
          {alreadyExpiredData.length > 0 && (
            <div className="space-y-4">
              <h3 className="text-rose-600 font-black text-sm uppercase tracking-widest flex items-center gap-2">
                <AlertTriangle size={16} />
                Expired Batches (Immediate Quarantine Required)
              </h3>
              <Table
                columns={columns}
                dataSource={alreadyExpiredData}
                loading={isLoading}
                rowKey="id"
                className="modern-table border border-rose-100 rounded-2xl"
              />
            </div>
          )}
          <div className="space-y-4">
            <h3 className="text-slate-900 font-black text-sm uppercase tracking-widest">
              Expiring within 90 days
            </h3>
            <Table
              columns={columns}
              dataSource={expiringSoonData}
              loading={isLoading}
              rowKey="id"
              className="modern-table"
            />
          </div>
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div>
        <h1 className="text-[28px] font-bold text-slate-900 tracking-tight">
          Inventory Alert Panel
        </h1>
        <p className="text-[15px] text-slate-500 mt-1 font-medium">
          Identify expiring batches, quarantine expired stock, and trigger vendor reorders.
        </p>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 p-6 shadow-sm">
        <Tabs
          activeKey={activeTab}
          onChange={(key) => setActiveTab(key)}
          items={tabItems}
          className="modern-tabs"
        />
      </div>
    </div>
  );
};

export default InventoryAlerts;
